/**
 * Workbook-level settings persistence for Phase 2 tagging/config recall.
 */
import { defaultEdgeCaseScanConfig, sanitizeEdgeCaseScanConfig, } from '@/services/anonymization/edgeCaseConfig';
const WORKBOOK_SETTINGS_KEY = 'recludeWorkbookSettingsV2';
const LEGACY_WORKBOOK_SETTINGS_KEY = 'xlsMaskerWorkbookSettingsV2';
const SETTINGS_VERSION = '2.0';
const validMatchingModes = ['exact', 'starts-with', 'includes'];
const validProtectedBehaviors = ['ask', 'skip', 'cancel'];
const validDesignations = ['Customer', 'Vendor', 'Employee', 'Custom'];
const saveDocumentSettings = async () => new Promise((resolve, reject) => {
    Office.context.document.settings.saveAsync((result) => {
        if (result.status === Office.AsyncResultStatus.Succeeded) {
            resolve();
        }
        else {
            reject(new Error(result.error?.message || 'Failed to save workbook settings.'));
        }
    });
});
const isTaggedRange = (value) => {
    if (!value || typeof value !== 'object') {
        return false;
    }
    const candidate = value;
    const hasDesignation = typeof candidate.designation === 'string' &&
        validDesignations.includes(candidate.designation);
    return typeof candidate.address === 'string' && hasDesignation;
};
const sanitizeTaggedRange = (taggedRange) => {
    const sanitizedAddress = taggedRange.address.trim();
    const sanitizedCustomDesignation = taggedRange.designation === 'Custom'
        ? taggedRange.customDesignation?.trim() || 'Custom'
        : undefined;
    const sanitizedRange = {
        id: taggedRange.id?.trim() || `${Date.now()}-${Math.random().toString(16).slice(2, 8)}`,
        address: sanitizedAddress,
        designation: taggedRange.designation,
    };
    if (sanitizedCustomDesignation) {
        sanitizedRange.customDesignation = sanitizedCustomDesignation;
    }
    return sanitizedRange;
};
const isPersistedWorkbookSettings = (value) => {
    if (!value || typeof value !== 'object') {
        return false;
    }
    const candidate = value;
    const hasTaggedRanges = Array.isArray(candidate.taggedRanges) && candidate.taggedRanges.every(isTaggedRange);
    const hasMatchingMode = typeof candidate.matchingMode === 'string' &&
        validMatchingModes.includes(candidate.matchingMode);
    const hasProtectedBehavior = typeof candidate.protectedSheetBehavior === 'string' &&
        validProtectedBehaviors.includes(candidate.protectedSheetBehavior);
    return (typeof candidate.version === 'string' &&
        typeof candidate.workbookGuid === 'string' &&
        typeof candidate.rememberSettings === 'boolean' &&
        hasTaggedRanges &&
        hasMatchingMode &&
        hasProtectedBehavior &&
        typeof candidate.updatedAt === 'string');
};
export const buildWorkbookSettingsPayload = (workbookGuid, rememberSettings, taggedRanges, matchingMode, protectedSheetBehavior, edgeCaseScanConfig) => ({
    version: SETTINGS_VERSION,
    workbookGuid,
    rememberSettings,
    taggedRanges: taggedRanges.map(sanitizeTaggedRange).filter((range) => range.address.length > 0),
    matchingMode,
    protectedSheetBehavior,
    edgeCaseScanConfig: sanitizeEdgeCaseScanConfig(edgeCaseScanConfig),
    updatedAt: new Date().toISOString(),
});
export const loadWorkbookSettings = async (workbookGuid) => {
    const rawSettings = Office.context.document.settings.get(WORKBOOK_SETTINGS_KEY) ||
        Office.context.document.settings.get(LEGACY_WORKBOOK_SETTINGS_KEY);
    if (!rawSettings) {
        return null;
    }
    if (!isPersistedWorkbookSettings(rawSettings)) {
        return null;
    }
    if (rawSettings.workbookGuid !== workbookGuid) {
        return null;
    }
    return {
        ...rawSettings,
        taggedRanges: rawSettings.taggedRanges.map(sanitizeTaggedRange),
        edgeCaseScanConfig: sanitizeEdgeCaseScanConfig(rawSettings.edgeCaseScanConfig, defaultEdgeCaseScanConfig()),
    };
};
export const saveWorkbookSettings = async (settings) => {
    Office.context.document.settings.set(WORKBOOK_SETTINGS_KEY, settings);
    await saveDocumentSettings();
};
export const clearWorkbookSettings = async () => {
    Office.context.document.settings.remove(WORKBOOK_SETTINGS_KEY);
    Office.context.document.settings.remove(LEGACY_WORKBOOK_SETTINGS_KEY);
    await saveDocumentSettings();
};
