/**
 * Excel Context Slice
 *
 * This slice manages the Excel workbook context including current workbook
 * information, worksheet data, and selected ranges.
 */
import { createSlice } from '@reduxjs/toolkit';
const initialState = {
    context: {
        workbook: null,
        worksheet: null,
        selectedRange: null,
        isConnected: false,
    },
    workbookInfo: null,
    currentWorksheet: null,
    selectedRange: null,
    isConnected: false,
    lastError: null,
};
export const excelSlice = createSlice({
    name: 'excel',
    initialState,
    reducers: {
        setContext: (state, action) => {
            state.context = { ...state.context, ...action.payload };
        },
        setWorkbookInfo: (state, action) => {
            state.workbookInfo = action.payload;
        },
        setCurrentWorksheet: (state, action) => {
            state.currentWorksheet = action.payload;
        },
        setSelectedRange: (state, action) => {
            state.selectedRange = action.payload;
        },
        setConnected: (state, action) => {
            state.isConnected = action.payload;
            state.context.isConnected = action.payload;
        },
        setError: (state, action) => {
            state.lastError = action.payload;
        },
        clearError: (state) => {
            state.lastError = null;
        },
        resetState: () => {
            return initialState;
        },
    },
});
export const { setContext, setWorkbookInfo, setCurrentWorksheet, setSelectedRange, setConnected, setError, clearError, resetState, } = excelSlice.actions;
export default excelSlice.reducer;
