export const edgeCaseMatchTypes = ['block-text', 'formula-string'];
export const defaultEdgeCaseScanConfig = () => ({
    searchBlockText: true,
    searchFormulaLiterals: true,
    blockTextMinCharacters: 80,
});
const isRecord = (value) => typeof value === 'object' && value !== null && !Array.isArray(value);
const toBoolean = (value, fallback) => typeof value === 'boolean' ? value : fallback;
const toPositiveNumber = (value, fallback) => {
    if (typeof value !== 'number' || Number.isNaN(value) || !Number.isFinite(value)) {
        return fallback;
    }
    return Math.max(20, Math.round(value));
};
export const sanitizeEdgeCaseScanConfig = (value, fallback = defaultEdgeCaseScanConfig()) => {
    if (!isRecord(value)) {
        return fallback;
    }
    return {
        searchBlockText: toBoolean(value.searchBlockText, fallback.searchBlockText),
        searchFormulaLiterals: toBoolean(value.searchFormulaLiterals, fallback.searchFormulaLiterals),
        blockTextMinCharacters: toPositiveNumber(value.blockTextMinCharacters, fallback.blockTextMinCharacters),
    };
};
export const isLikelyBlockText = (value, minLength) => {
    if (value.length < minLength) {
        return false;
    }
    if (value.includes('\n')) {
        return true;
    }
    const words = value.trim().split(/\s+/);
    return words.length >= 8;
};
export const buildEdgeCaseGroupKey = (matchType, mapping) => `${matchType}:${mapping.designation}:${mapping.sourceNormalized}`;
